class Solution:
    def crackSafe(self, n: int, k: int) -> str:
        total = k ** n
        graph = {}
        for i in range(total):
            node = str(i).zfill(n)
            graph[node] = []
            for j in range(k):
                neighbor = node[1:] + str(j)
                graph[node].append(neighbor)

        ans = []
        visited = set()
        def dfs(node):
            for neighbor in graph[node]:
                if (node, neighbor) not in visited:
                    visited.add((node, neighbor))
                    dfs(neighbor)
                    ans.append(neighbor[-1])
            return

        start = '0' * n
        dfs(start)
        ans.append(start[:n-1])
        return ''.join(ans[::-1])

